INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('001aa635ebbe4c45b78eda4b81646b2e', 'getFileInfoList(String arg0)', 'String', '/**\n *\n * @param path 目录相对路径\n * @return 文件信息\n */\n var path = \"./XXX\";\n var res = kutils.getFileInfoList(path);\n', '根据目录获取目录下的所有文件信息，包括文件名，文件路径(相对)，文件大小', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('006083f6cee9404d90700823dc649691', 'removeCache(String arg0, String arg1)', 'void', '/**\n *\n * @param cacheName  缓存名\n * @param key  缓存key\n */\n\nvar cacheName = \"\";\nvar key = \"\";\nvar res = kutils.removeCache(cacheName, key);\n', '清除缓存', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('01c132aa0142427ea5ee42872a1be51e', 'rsaDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param text  需要解密的数据\n * @param publicKey  key\n * @return  解密后的数据\n */\n\nvar text = \"\";\nvar publicKey = \"\";\nvar res = kutils.rsaDecode(text, publicKey);\n', 'RSA解密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('01f7493ec33a46ab9953282da0c5ad3e', 'startFlow(Map<String, String> arg0, String arg1, String arg2)', 'String', '/**\n *\n * @param AomServerParam AomServerParam {serverip: \"\",serverport:\"\",username:\"\",password:\"\"...}\n * @param flowId\n * @param execId\n * @return JSONString\n\n * var res = aomApi.startFlow(...);\n */\n', '执行流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('06852048a82347b0aa8ae1eaf43c42c6', 'fileImgDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param key\n * @param fileName\n * @return base64字符串\n * @throws Exception\n */\n\n\n var key = \"\";\n var fileName = \"\";\n var res = kutils.fileImgDecode(key, fileName);\n', '图片文件解密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0686d7593f4f41b88609cadc4266f7f2', 'transfer(String arg0, String arg1, int arg2, String arg3)', 'String', '/**\n *\n  * 转派:根据已有任务id、任务类型、参与者创建新的任务\n  *\n  * @param taskId   任务id\n  * @param operator 操作人id\n  * @param taskType 任务类型（0：主办任务；1：协办任务）\n  * @param actors   参与者集合，多人用逗号隔开\n  * @return json(List<Task>) 创建任务集合\n\nvar res = flowTask.transfer(\'a\', \'1\', 0, \'1\');\n', '根据已有任务id、任务类型、参与者创建新的任务', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('069b11eea3a340b6a7e7fac98fad3f2a', 'getEncoding(String arg0)', 'String', '/**\n *\n * @param string 待校验字符串\n * @return 字符串编码\n */\n var str = \"123\";\n var res = kutils.getEncoding(str);\n', '字符串编码验证', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('06fb924802f14180aab1b637a5eb3223', 'httpBase64Upload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3, Map<String, String> arg4)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list\n * @param params Map<String,String>\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// base64文件内容\nvar fileContent = \"dGVzdC5wZGY=\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件内容\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'content\', fileContent);\nlist.add(fileMap);\n\n// 除了文件外的其他请求参数\nvar params = new HashMap();\nparams.put(\"abc\", \"123\");\n\nvar res = kutils.httpBase64Upload(key, url, headers, list, params);\n', 'base64文件上传', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0a1137965ca9403f98630a42c623b63a', 'getFlowStateByID(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param flowId\n * @return JSONString\n\n * var res = aomApi.getFlowStateByID(...);\n */\n', '获取指定 ID 流程状态', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0a2011956d1642a38d32c77ce556b0d7', 'search(String arg0, String arg1)', 'String', '/**\n * 查询\n *\n * @param indexName 索引名称\n * @param queryString       查询条件\n * @return 渲染结果\n *  成功： {\"data\":{},\"success\":true}\n *  失败： {\"errorMsg\":\"异常信息\",\"success\":false}\n */', '查询', 'a63dad4c821944478db80bd4b2dbd9e4', '2022-08-18 16:05:53', '94123ca363dc4dfaa62a6bb5dcd3bf50', '2022-08-18 16:05:53', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0b743bc0fa5749d4bf96a59012808dd6', 'getTableColumn(Map<String, String> arg0, String arg1, String arg2)', 'String', '', '', '0326119307e146ab97be95cc5d029f4c', '2022-07-19 09:18:35', '8c263f81d2b14784906787d67ce58b47', '2022-07-19 09:18:35', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0ccab7bd44424825a4e977eafbcfb355', 'sm4Encode_CBC(String arg0, String arg1)', 'String', '/**\n *\n * @param key\n * @param text  需要加密的数据\n * @return  加密后的数据\n */\n\nvar key = \"\";\nvar text = \"\";\nvar res = kutils.sm4Encode_CBC(key, text);\n', '国密4CBC模式加密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0da1114c70ce436ca3ab37ff6b33b6a4', 'getAllTableByDB(String arg0, String arg1, String arg2, String arg3)', 'String', '/**\n * 查询指定数据库的所有表名\n *\n * @param username 用户名\n * @param password 密码\n * @param jdbcUrl  jdbc链接\n * @param dbName   数据库名称/模式名称\n * @return 逗号分割的所有表名\n * 注意：如果是postgresql数据库，此方法将只能返回连接时使用的数据库下的所有表，数据库特性导致\n *\n * dbConsoleApi.getAllTableByDB(username, password, jdbcUrl,dbName);\n */\n', '查询元数据：查询指定数据库的所有表名', 'e3ed9daac1c54e63b8a38bda317c7756', '2022-09-13 11:10:59', '8c263f81d2b14784906787d67ce58b47', '2022-09-13 11:10:59', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0e3fdfc5b52c45789357646ce272a46f', 'setCache(String arg0, String arg1, String arg2, int arg3)', 'void', '/**\n *\n * @param cacheName  缓存名\n * @param key  缓存key\n * @param value  缓存value\n * @param maxLifetime  过期时间 int\n */\n\nvar cacheName = \"\";\nvar key = \"\";\nvar value = \"\";\nvar maxLifetime = 6000;\nvar res = kutils.setCache(cacheName, key, value);\n', '设置缓存和过期时间', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('0e426dbac9ff47d9a0620e64bff41b1c', 'fileEncode(String arg0, String arg1, String arg2)', 'void', '/**\n *\n * @param key\n * @param content : 文件内容\n * @param fileName : 文件名\n * @return\n */\n\n\n var key = \"\";\n var content = \"\";\n var fileName = \"\";\n kutils.fileEncode(key, content, fileName);\n', '文件内容加密:国密4 ECB模式加密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('100afdbee1274e39b24bd5f1ee3b35ce', 'createNewTask(String arg0, int arg1, String arg2)', 'String', '/**\n *\n * 根据已有任务id、任务类型、参与者创建新的任务\n *\n * @param taskId   主办任务id\n * @param taskType 任务类型\n * @param actors   参与者集合，多人用逗号隔开\n * @return json(List<Task>) 创建任务集合\n\nvar res = flowTask.createNewTask(\'a\', 0, \'1\');\n', '根据已有任务id、任务类型、参与者创建新的任务', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('10886caf79fe48608513c5fa52a5a92d', 'deploy(String arg0, String arg1)', 'String', '/**\n *\n * 根據輸入文本字符串，部署流程定义\n * @param def 流程定义文本\n * @param creator 流程创建人\n * @return String 流程定义id\n\nvar res = flowRepository.deploy(\'{..}\', \'1\');\n', '根據輸入文本字符串，部署流程定义', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('10f12f1d52b94761a0d753d41fae775b', 'getProcessById(String arg0)', 'String', '/**\n *\n * 根据主键ID获取流程定义对象\n * @param id 流程定义id\n * @return Process 流程定义对象\n\nvar res = flowDefine.getProcessById(\'a\');\n', '根据主键ID获取流程定义对象', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('124e707ac34e4805bf583f2e4906fa15', 'execute(Map<String, String> arg0, String arg1, String arg2)', 'String', '', '', '726c447b3f2141c293a9fd8696d3b836', '2022-06-27 16:51:29', 'd4040ae0800844d99406157b798bae01', '2022-06-27 16:51:29', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('135b1843cbf64aa2aeed5dd55c8db6b4', 'httpBase64Upload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// base64文件内容\nvar fileContent = \"dGVzdC5wZGY=\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件内容\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'content\', fileContent);\nlist.add(fileMap);\n\nvar res = kutils.httpBase64Upload(key, url, headers, list);\n', 'base64文件上传', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('13fd0259df6f4723b16ae339b13335a9', 'base64Encode(String arg0)', 'String', '/**\n *\n * @param data  需要加密的数据\n * @return  加密后的数据\n */\n\nvar data = \"\";\nvar res = kutils.base64Encode(data);\n', 'base64加密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('142fd60ddd6a40ae9e769943e5a1ac2f', 'fileMove(String arg0, String arg1)', 'String', '/**\n *\n * @param from\n * @param to\n * @return\n */\n\n\n var from = \"\";\n var to = \"\";\n var res = kutils.fileMove(from, to);\n', '文件移动', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('14a38cdc4bd248f49fc8b78bc27e75ac', 'getNativeNodeModel(String arg0, String arg1)', 'com.kingsware.workflow.model.NodeModel', '/**\n *\n * 根据流程定义模型id和任务定义模型name获取当前节点模型对象\n * @param processId 流程定义模型id\n * @param taskName 任务定义模型name（注意是name字段，区别于displayName字段）\n * @return NodeModel\n\nvar res = flowDefine.getNativeNodeModel(\'a\', \'1\');\n', '根据流程定义模型id和任务定义模型name获取当前节点模型对象', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('177a72d56a414cbd90cc4402ab0da4f7', 'getActiveTasks(String arg0)', 'String', '/**\n *\n * 根据filter查询活动任务\n * @param filter 查询过滤器\n * @return json(List<Task>) 活动任务集合\n */\n\nvar filter = \'{\"operator\":\"1\"}\';\nvar res = flowTask.getActiveTasks(filter);\n', '查询活动任务', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('18e50d68e4e940f2ae945e45f0e4bfd0', 'fileRead(String arg0, String arg1)', 'String', '/**\n *\n * @param fileName\n * @param charset\n */\n\n\n var fileName = \"\";\n var charset = \"\";\n var res = kutils.fileRead(fileName, charset);\n', '读取文件', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1a48101ec9da44c6bde8fa8eb250b890', 'startFlow(Map<String, String> arg0, String arg1, List<Map<String, Object>> arg2, List<Map<String, Object>> arg3, List<Map<String, Object>> arg4)', 'String', '/**\n * @param aomServerParam\n * @param flowId\n * @param objectParams 节点参数 List<Map<String, Object>>\n * @param agentParams 机器参数 List<Map<String, Object>>\n * @param vclParams 组件节点参数 List<Map<String, Object>>\n * @return JSONString\n *\n * var aomServerParam = {\n *    \"serverip\":\"\",\n *    \"serverport\":\"\",\n *    ......\n * }\n *\n * var objectParam1 = {\n *    \"objectName\": \"\",\n *    \"paramName\": \"\",\n *    \"paramValue\": \"\",\n *    \"paramIsDes\": false\n * }\n * var objectParamList = [];\n * objectParamList.push(objectParam1);\n\n * var agentParam1 = {\n *    \"agentParamName\": \"\",\n *    \"agentParamValue\": \"\"\n * }\n * var agentParamList = [];\n * agentParamList.push(agentParam1);\n\n * var vclParam1 = {\n *    \"VCLObjectName\": \"\",\n *    \"VCLParamValue\": \"\"\n * }\n * var vclParamList = [];\n * vclParamList.push(vclParam1);\n * var result = aomApi.startFlow(aomServerParam, \"flowId\", objectParamList, agentParamList, vclParamList)\n *\n */\n', '执行流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1a5d7acb1362472387204a6ff151cb3c', 'deleteCCInst(String arg0, String arg1)', 'void', '/**\n *\n * 删除抄送记录\n * @param instId 流程实例id\n * @param actorId 参与者id\n\nvar res = flowInst.deleteCCInst(\'a\', \'f\');\n', '删除抄送记录', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1c6b79e0884a403ba54f68750252f4ce', 'sm4Decode_ECB(String arg0, String arg1)', 'String', '/**\n *\n * @param key\n * @param text  需要解密的数据\n * @return  解密后的数据\n */\n\nvar key = \"\";\nvar text = \"\";\nvar res = kutils.sm4Decode_ECB(key, text);\n', '国密4ECB模式解密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1c922d7eeb8f4bffb8de475b9e38371f', 'getGcutil(String arg0, int arg1, String arg2, String arg3, long arg4, String arg5, String arg6)', 'String', ' /**\n  *\n  * @param host ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param timeout 超时时长\n  * @param charset 编码\n  * @param pid pid\n  * @return JSONString gcutil信息\n  *\n  * var res = monitorApi.getGcutil(\"ip\",\"port\",\"username\",\"password\", 30000, \"UTF-8\", \"pid\");\n  */\n', '根据pid获取gcutil信息', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1ce741a88d7a47a588cae1c7fc940f88', 'getBulkTable(String arg0, String arg1, int arg2, String arg3, String arg4, String arg5, String arg6, String arg7, String arg8, String arg9, List<String> arg10, long arg11)', 'String', '/**\n *\n * @param host\n * @param version v1、v2c、v3\n * @param port 端口\n * @param community 团体字（v1, v2c）\n * @param userName 用户名 （v2及以下版本填null)\n * @param securityLevel 安全级别（v2及以下版本填null)：分别为noAuthNoPriv（不认证也不加密）、authNoPriv（认证但是不加密）、authPriv（既认证又加密）\n * @param authenticationProtocol 验证协议（v2及以下版本填null)：MD5、SHA\n * @param authenticationPassphrase 验证字符串（v2及以下版本填null)\n * @param privacyProtocol 加密协议（v2及以下版本填null)：DES、3DES、AES128、AES192、AES256\n * @param privacyPassphrase 加密字符串（v2及以下版本填null)\n * @param oids 每个oid对应表的每一列\n * @param timeout 超时时间，毫秒单位\n * @return JSONString\n *\n * var oids = [\".1.3.6.1.2.1.1\"];\n * var tableRows =  snmpApi.getBulkTable(\"1.1.1.1\", \"v2c\", 161, \"public\", null, null, null, null, null, null, oids, 5000);\n * tableRows = JSON.parse(tableRows);\n * for (var i in tableRows) {\n *      var row = tableRows[i];\n *      var index = row[\"index\"];\n *      var variables = row[\"columns\"];\n * }\n */\n', '使用getbulk获取表对象的列变量信息，每个oid对应表的每一列', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1df74bcb147a4f37aa7f6a5d89fad73a', 'removeIndexes(String arg0, String arg1)', 'String', '/**\n * 删除索引\n *\n * @param indexName 索引名称\n * @param queries   查询条件\n * @return 渲染结果\n *  成功： {\"data\":1,\"success\":true}\n *  失败： {\"errorMsg\":\"异常信息\",\"success\":false}\n */', '通过查询条件删除索引', 'a63dad4c821944478db80bd4b2dbd9e4', '2022-08-18 16:05:53', '94123ca363dc4dfaa62a6bb5dcd3bf50', '2022-08-18 16:05:53', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1dfd09c4d5ed4fa49960a00b19c43911', 'fileDirectory(String arg0)', 'void', '/**\n *\n * @param path\n */\n\n var path = \"\";\n kutils.fileDirectory(path);\n', '创建多级目录', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('1e0357c13bd649b292880d11990a09ff', 'urlEncodeOfAlibaba(String arg0)', 'String', '/**\n *\n * @param value 文本\n * @return  编码后的内容\n */\n\nvar value = \"\";\nvar res = kutils.urlEncodeOfAlibaba(value);\n', '阿里专有url编码方式', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
