INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('2064604d0efe461782f418c942c68953', 'getAllAgent(Map<String, String> arg0)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @return JSONString\n\n * var res = aomApi.getAllAgent(...);\n */\n', '获取所有代理信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('213d8c232851463496222f90a7d4f9ca', 'unZip(String arg0, String arg1, String arg2)', 'String', '/**\n *\n * @param filePath 源压缩文件路径和压缩文件名称\n * @param unZipPath 解压目录\n * @param password 密码\n * @return 解压缩成功/失败\n * @throws IOException 解压缩文件时发生异常\n */\n\n\n var filePath = \"D:\\新建zip文件.zip\";\n var unZipPath = \"D:\\新建文件夹\";\n var password = \"12345\";\n var res = kutils.unZip(filePath, unZipPath, password);\n', '文件解压缩', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('2198f7e6db32458d997f6d75bcb36677', 'aesEncode(String arg0, String arg1)', 'String', '/**\n *\n * @param str 代加密密文\n * @param key base64加密后的密钥\n * @return 密文\n * @throws Exception\n */\n\n var str = \"\";\n var key = \"\";\n var res = kutils.aesEncode(str, key);\n', 'AES加密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('22c49b712dd64c8eac71e3fdc1f7a68c', 'sendMail(String arg0, String arg1, String arg2, String[) arg3, String arg4, String arg5]', 'String', '/**\n *\n * @param host 邮件服务器\n * @param username 发件人\n * @param password 密码\n * @param address 收件人地址数组\n * @param title 邮件标题\n * @param content 邮件内容\n * @return 发送成功/失败\n *\n * var res = monitorApi.sendMail(\"host\",\"username\",\"password\",[\"address\"], \"title\", \"content\")\n */\n', '发送邮件', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('235c534b2d524a34ae26a3d125554f60', 'httpBase64Upload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// base64文件内容\nvar fileContent = \"dGVzdC5wZGY=\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件内容\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'content\', fileContent);\nlist.add(fileMap);\n\nvar res = kutils.httpBase64Upload(key, url, headers, list);\n', 'base64文件上传', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('24b3b28a0946467b86c355ec349e8866', 'httpFileUpload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// 文件在服务器上的相对路径，包括文件名，例：upload/test/test.pdf\nvar fileLocal = \"upload/test/test.pdf\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件信息\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'filename\', fileLocal);\nlist.add(fileMap);\n\nvar res = kutils.httpFileUpload(key, url, headers, list);\n', '只需要上传文件的请求，不包括其他参数', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('25dd70d159e74092bd39f6ec6b326b86', 'getComponentList(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param scriptGroupId 脚本分组Id\n * @return JSONString\n\n * var res = aomApi.getComponentList(...);\n */\n', '获取组件列表信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('25de5ab382864b16b75883297e7de628', 'getLastFlowInfo(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param programId\n * @return JSONString\n\n * var res = aomApi.getLastFlowInfo(...);\n */\n', '获取流程上一次信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('26db40b991774101a8e54b54390becc8', 'getAllTable(String arg0, String arg1, String arg2)', 'String', '/**\n * 获取所有表名\n *\n * @param username 用户名\n * @param password 密码\n * @param jdbcUrl  jdbc链接\n * @return 逗号分割的所有表名\n *\n * dbConsoleApi.getAllTable(username, password, jdbcUrl);\n */\n', '查询元数据：获取所有表名', 'e3ed9daac1c54e63b8a38bda317c7756', '2022-09-13 11:10:59', '8c263f81d2b14784906787d67ce58b47', '2022-09-13 11:10:59', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('26ecdeeddde24b648efb01a06431218c', 'execute(Map<String, String> arg0, String arg1, String arg2)', 'String', '', '', '0326119307e146ab97be95cc5d029f4c', '2022-07-19 09:18:35', '8c263f81d2b14784906787d67ce58b47', '2022-07-19 09:18:35', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('27f1979deb79412a94ed0d34da4d0c1e', 'take(String arg0, String arg1)', 'String', '/**\n *\n * 提取：根据任务主键ID，操作人ID提取任务\n * 提取任务相当于预受理操作，仅仅标识此任务只能由此操作人处理\n *\n * @param taskId   任务id\n * @param operator 操作人id\n * @return json(Task) 任务对象，多人用逗号隔开\n\nvar res = flowTask.take(\'a\', \'1\');\n', '根据任务主键ID，操作人ID提取任务', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('28873866e5464e669cb6b82aa07f5af0', 'getWebTaskInfoList(Map<String, String> arg0, String arg1, int arg2, int arg3, String arg4, String arg5, String arg6)', 'String', '/**\n *\n * @param aomServerParam\n * @param taskIDs	任务ID，逗号分割，为空表示全部任务\n * @param sYear\n * @param eYear\n * @param startDate\n * @param endDate\n * @param days	获取的天数，逗号分割，例如：\"20220227,20220228\"\n * @return JSONString\n\n * var res = aomApi.getWebTaskInfoList(...);\n */\n', '获取作业调度信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('2904c6e8edc84cb1a155282885311a6d', 'removeCache(String arg0, String arg1)', 'void', '/**\n *\n * @param cacheName  缓存名\n * @param key  缓存key\n */\n\nvar cacheName = \"\";\nvar key = \"\";\nvar res = kutils.removeCache(cacheName, key);\n', '清除缓存', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('2924eca9364a4eae87b4db106cc1d848', 'httpFileUpload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// 文件在服务器上的相对路径，包括文件名，例：upload/test/test.pdf\nvar fileLocal = \"upload/test/test.pdf\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件信息\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'filename\', fileLocal);\nlist.add(fileMap);\n\nvar res = kutils.httpFileUpload(key, url, headers, list);\n', '只需要上传文件的请求，不包括其他参数', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('29ea3da482a449a7ab29e9f53d3cb892', 'reset()', 'void', '', '', '0326119307e146ab97be95cc5d029f4c', '2022-07-19 09:18:35', '8c263f81d2b14784906787d67ce58b47', '2022-07-19 09:18:35', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('2bec080f118149a89d85d0aad17427ba', 'buildConnection(String arg0, String arg1, String arg2)', 'String', '/**\n * 新建连接\n *\n * @param username 用户名\n * @param password 密码\n * @param jdbcUrl  jdbc链接\n * @return 返回boolean类型\n *\n * dbConsoleApi.buildConnection(username, password, jdbcUrl);\n */\n', '新建连接', 'e3ed9daac1c54e63b8a38bda317c7756', '2022-09-13 11:10:59', '8c263f81d2b14784906787d67ce58b47', '2022-09-13 11:10:59', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('2e067eac78264ebcb1ba32814bccb7d6', 'fileCopy(String arg0, String arg1)', 'void', '/**\n *\n * @param oldFileName\n * @param newFileName\n */\n\n\n var oldFileName = \"\";\n var newFileName = \"\";\n kutils.fileCopy(oldFileName, newFileName);\n', '文件拷贝', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
