INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('36c711256c2546ae8d737aded2f711f0', 'httpPostForm(String arg0, String arg1, Map<String, String> arg2, Map<String, String> arg3)', 'String', '/**\n *\n * @param url 请求地址\n * @param contentType Content-Type\n * @param headers 请求头 Map<String,String>\n * @param formParams 请求体，Map<String,String>\n * @return\n * @throws Exception\n */\nvar url = \"\";\nvar contentType = \"\";\nvar headers = {};\nvar formParams = {};\n\nvar res = kutils.httpPostForm(url, contentType, headers, formParams);\n', 'http post请求，请求参数是map格式', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
