INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('4682cac2a0764b1c990b051ccf14deb8', 'shell(String arg0, int arg1, String arg2, String arg3, String arg4, long arg5, String arg6)', 'String', '/**\n  * @param host 主机ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param command 命令\n  * @param timeout 超时时间(毫秒)\n  * @param charset 编码\n  * @return\n  * @throws Exception\n  *\n  * var host = \"10.11.2.215\", port = 22, username = \"root\", password = \"Kingsware##1228\", command = \"echo hello\", timeout = 30000, charset = \"UTF-8\";\n  * var result = sshApi.shell(host, port, username, password, command, timeout, charset);\n  *\n  */\n', 'ssh执行shell脚本', '518ead98cd5247eea5e0dd9f3f8ff020', '2022-07-14 12:27:21', '8c263f81d2b14784906787d67ce58b47', '2022-07-14 12:27:21', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('470d7b8624e940d8ba6b99b13004c3f2', 'startFlow(Map<String, String> arg0, String arg1, String arg2, List<Map<String, Object>> arg3, List<Map<String, Object>> arg4, List<Map<String, Object>> arg5)', 'String', '/**\n * @param aomServerParam\n * @param flowId\n * @param execId\n * @param objectParams 节点参数 List<Map<String, Object>>\n * @param agentParams 机器参数 List<Map<String, Object>>\n * @param vclParams 组件节点参数 List<Map<String, Object>>\n * @return JSONString\n *\n * var aomServerParam = {\n *    \"serverip\":\"\",\n *    \"serverport\":\"\",\n *    ......\n * }\n *\n * var objectParam1 = {\n *    \"objectName\": \"\",\n *    \"paramName\": \"\",\n *    \"paramValue\": \"\",\n *    \"paramIsDes\": false\n * }\n * var objectParamList = [];\n * objectParamList.push(objectParam1);\n\n * var agentParam1 = {\n *    \"agentParamName\": \"\",\n *    \"agentParamValue\": \"\"\n * }\n * var agentParamList = [];\n * agentParamList.push(agentParam1);\n\n * var vclParam1 = {\n *    \"VCLObjectName\": \"\",\n *    \"VCLParamValue\": \"\"\n * }\n * var vclParamList = [];\n * vclParamList.push(vclParam1);\n * var result = aomApi.startFlow(aomServerParam, \"flowId\", \"execId\", objectParamList, agentParamList, vclParamList)\n *\n */\n', '执行流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('4717b1fd1cc1443e8ce016314c8b2677', 'notice()', 'void', '', '私人专用插件，功能开发中，不稳定，请使用 netProtocol 插件进行ssh操作！！！', '518ead98cd5247eea5e0dd9f3f8ff020', '2022-07-14 12:27:21', '8c263f81d2b14784906787d67ce58b47', '2022-07-14 12:27:21', NULL, 0);
