INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('4dcaff3e59b4404fa87aab7ec40a4889', 'desDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param str base64加密的密文\n * @param key base64加密后的密钥\n * @return 解密后的数据\n * @throws Exception\n */\n\n var str = \"\";\n var key = \"\";\n var res = kutils.desDecode(str, key);\n', 'DES解密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('4e1225cbfa304efabc05cecdf93e98ce', 'sm4Encode_CBC(String arg0, String arg1)', 'String', '/**\n *\n * @param key\n * @param text  需要加密的数据\n * @return  加密后的数据\n */\n\nvar key = \"\";\nvar text = \"\";\nvar res = kutils.sm4Encode_CBC(key, text);\n', '国密4CBC模式加密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('4f6bc66679574b78b77118fd823aa874', 'getHistTask(String arg0)', 'String', '/**\n *\n * 根据任务ID获取历史任务对象\n *\n * @param taskId 历史任务id\n * @return json(HistoryTask) 历史任务对象\n\nvar res = flowTask.getHistTask(\'a\');\n', '根据任务ID获取历史任务对象', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('4ff0200da8a94334823acbb7f0d4d9f7', 'pauseFlow(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param execId\n * @return JSONString\n\n * var res = aomApi.pauseFlow(...);\n */\n', '暂停流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('514c7127e8f946f3ad445e72cde30fd8', 'createCCInst(String arg0, String arg1, String arg2)', 'void', '/**\n *\n * 抄送：创建抄送实例\n * @param instId 流程实例id\n * @param actorIds 参与者id\n * @param creator 创建人id\n\nvar res = flowInst.createCCInst(\'a\', \'s\', \'f\');\n', '抄送：创建抄送实例', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5184416636b34f5a837defd8bdaf2b81', 'addTaskActor(String arg0, int arg1, String arg2)', 'String', '/**\n *\n * 加签：向指定的任务id添加参与者\n *\n * @param taskId      任务id\n * @param performType 参与方式（0：普通任务；1：参与者会签任务）\n * @param actors      参与者，多人用逗号隔开\n * @return 字符串：SUCCESS\n\nvar res = flowTask.addTaskActor(\'a\', 0, \'1\');\n', '加签：向指定的任务id添加参与者', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('52a04f86d5e0409fabbc73e06b9faa0e', 'startInstanceByName(String arg0)', 'String', '/**\n *\n * 根据流程名称启动流程实例\n * @param name 流程定义名称\n * @return Workflow 流程实例\n\nvar res = flowRepository.startInstanceByName(\'aa\');\n', '根据流程名称启动流程实例', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('57b44c347dbe40f0806022cda89dae1d', 'getTableTree(String arg0, String arg1, String arg2)', 'String', '/**\n * 获取所有数据库\n *\n * @param username 用户名\n * @param password 密码\n * @param jdbcUrl  jdbc链接\n * @return 返回[{\"database\":\"A\",\"table\":[\'a\',\'b\']},{\"database\":\"B\",\"table\":[\'c\',\'d\']}]的JSON字符串\n * 注意：如果是oracle数据库，此方法将只返回登录指定模式下的所有表来构造的文件树，原因是Oracle表太多，一次性构造，执行时间将会非常长\n *      其他数据库暂时没有此问题\n *\n * dbConsoleApi.getTableTree(username, password, jdbcUrl);\n */\n', '查询元数据：构造数据库文件树', 'e3ed9daac1c54e63b8a38bda317c7756', '2022-09-13 11:10:59', '8c263f81d2b14784906787d67ce58b47', '2022-09-13 11:10:59', NULL, 0);
