INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5a3cfa19282f4983a601b2319a229db6', 'getCache(String arg0)', 'String', '/**\n *\n * @param cacheName  缓存名\n */\n\nvar cacheName = \"\";\nvar res = kutils.getCache(cacheName);\n', '获取缓存列表', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5a875e0b9b1f483c8b3b658865086fd5', 'fileReadBase64(String arg0)', 'String', '/**\n *\n * @param fileName  文件名\n * @return  base64编码\n * @throws Exception    异常\n */\n\n\n var fileName = \"\";\n var res = kutils.fileReadBase64(fileName);\n', '读取文件转为base64', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5afb5086cfee4aebb8b782d6ef475b39', 'hmacSha1(String arg0, String arg1)', 'String', '/**\n *\n * @param content 待签名内容\n * @param secret 签名钥匙\n * @return   返回签名值\n */\n\n\nvar content = \"\";,\nvar secret = \"\";\nvar res = kutils.hmacSha1(content, secret);\n', 'HMac-SHA1签名', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5cdb8999bd294683b81b0f7a6cfb669b', 'exec(String arg0, int arg1, String arg2, String arg3, String arg4, boolean arg5, long arg6, String arg7)', 'String', '/**\n  * @param host 主机ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param command 命令\n  * @param pty true/false\n  * @param timeout 超时时间(毫秒)\n  * @param charset 编码\n  * @return\n  * @throws Exception\n  *\n  * var host = \"10.11.2.215\", port = 22, username = \"root\", password = \"Kingsware##1228\", command = \"echo hello\", timeout = 30000, charset = \"UTF-8\", pty = true;\n  * var result = sshApi.exec(host, port, username, password, command, pty, timeout, charset);\n  *\n  */\n', 'ssh是否使用pty执行命令', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5ef5ff373d91485a900becfe3979923b', 'httpBase64Upload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3, Map<String, String> arg4)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list\n * @param params Map<String,String>\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// base64文件内容\nvar fileContent = \"dGVzdC5wZGY=\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件内容\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'content\', fileContent);\nlist.add(fileMap);\n\n// 除了文件外的其他请求参数\nvar params = new HashMap();\nparams.put(\"abc\", \"123\");\n\nvar res = kutils.httpBase64Upload(key, url, headers, list, params);\n', 'base64文件上传', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('5f65d3ed7b1f480ba6293c46046c6792', 'fileDirectory(String arg0)', 'void', '/**\n *\n * @param path\n */\n\n var path = \"\";\n kutils.fileDirectory(path);\n', '创建多级目录', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('616cad59705d4c239c084c2e0c854024', 'getNow(String arg0)', 'String', '/**\n *\n * @param format 时间格式\n * @return  格式化时间\n */\n\nvar format = \"\";\nvar res = kutils.getNow(format);\n', '格式化当前时间', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('6236cd4dbd4c4522ae23ac4550401e7c', 'unZip(String arg0, String arg1, String arg2)', 'String', '/**\n *\n * @param filePath 源压缩文件路径和压缩文件名称\n * @param unZipPath 解压目录\n * @param password 密码\n * @return 解压缩成功/失败\n * @throws IOException 解压缩文件时发生异常\n */\n\n\n var filePath = \"D:\\新建zip文件.zip\";\n var unZipPath = \"D:\\新建文件夹\";\n var password = \"12345\";\n var res = kutils.unZip(filePath, unZipPath, password);\n', '文件解压缩', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('63ff73f6d04e41debbca378a5a566ee2', 'getAgentList(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param AgentGroupId\n * @return JSONString\n\n * var res = aomApi.getAgentList(...);\n */\n', '获取代理列表', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('64641916d14740e5aab24c44b4ef5977', 'aesDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param str base64加密的密文\n * @param key base64加密后的密钥\n * @return 解密后的数据\n * @throws Exception\n */\n\n var str = \"\";\n var key = \"\";\n var res = kutils.aesDecode(str, key);\n', 'AES解密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('65fbc0db81974ac78aa4c7092850f2b2', 'getHistoryTaskActorsByTaskId(String arg0)', 'String', '/**\n *\n * 根据任务ID获取历史任务参与者数组\n * @param taskId 历史任务id\n * @return String 历史参与者id数组\n\nvar res = flowTask.getHistoryTaskActorsByTaskId(\'a\');\n', '根据任务ID获取历史任务参与者数组', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('6803e787c1c9444a92f52e4680db8098', 'callComponentDirectById(Map<String, String> arg0, String arg1, String arg2, Map<String, Object> arg3)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param agentIp\n * @param scriptId   组件Id\n * @param paramObj   组件参数\n * @return JSONString\n *\n *  var res = aomApi.callComponentDirectById(...);\n */\n', '通过组件Id执行并直接返回', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('68b5e65c95374f7c91317ecc5f314229', 'getAllDB(String arg0, String arg1, String arg2)', 'String', '/**\n * 获取所有数据库\n *\n * @param username 用户名\n * @param password 密码\n * @param jdbcUrl  jdbc链接\n * @return 逗号分割的所有数据库名\n * 注意：如果是postgresql数据库，此方法将只能返回连接时使用的数据库，数据库特性导致\n *\n * dbConsoleApi.getAllDB(username, password, jdbcUrl);\n */\n', '查询元数据：获取所有数据库', 'e3ed9daac1c54e63b8a38bda317c7756', '2022-09-13 11:10:59', '8c263f81d2b14784906787d67ce58b47', '2022-09-13 11:10:59', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('6a17c8c2a0f747f5a8fbf2c38ca5eed6', 'getVariable(String arg0, String arg1, int arg2, String arg3, String arg4, String arg5, String arg6, String arg7, String arg8, String arg9, List<String> arg10, long arg11)', 'String', '/**\n *\n * @param host\n * @param version v1、v2c、v3\n * @param port 端口\n * @param community 团体字（v1, v2c）\n * @param userName 用户名 （v2及以下版本填null)\n * @param securityLevel 安全级别（v2及以下版本填null)：分别为noAuthNoPriv（不认证也不加密）、authNoPriv（认证但是不加密）、authPriv（既认证又加密）\n * @param authenticationProtocol 验证协议（v2及以下版本填null)：MD5、SHA\n * @param authenticationPassphrase 验证字符串（v2及以下版本填null)\n * @param privacyProtocol 加密协议（v2及以下版本填null)：DES、3DES、AES128、AES192、AES256\n * @param privacyPassphrase 加密字符串（v2及以下版本填null)\n * @param oids 对象标识符，一个oid对应一个标量\n * @param timeout 超时时间，毫秒单位\n * @return JSONString\n * @throws IOException\n * var oids = [\".1.3.6.1.2.1.1.5.0\"];\n * var variables = snmpApi.getVariable(\"1.1.1.1\", \"v2c\", 161, \"kingsware\", null, null, null , null, null, null, oids, 5000);\n * variables = JSON.parse(variables);\n * for (var i in variables) {\n *      var result = variables[i];\n *      ...\n * }\n */\n', '使用get方式获取多个标量的信息', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('6aaa2268eb014ea3b698e1088e1acdbe', 'md5Encode(String arg0)', 'String', '/**\n *\n * @param text  需要加密的数据\n * @return  解加后的数据\n */\n\nvar text = \"\";\nvar res = kutils.md5Encode(text);\n', 'MD5加密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('6bc3333b394b4ce3934e6e01a0ae3c6c', 'fileImgEncode(String arg0, String arg1)', 'void', '/**\n *\n * @param key\n * @param fileName\n * @throws Exception\n */\n\n\n var key = \"\";\n var fileName = \"\";\n kutils.fileImgEncode(key, fileName);\n', '图片文件加密:国密4', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('6da2e85e55f84a60ab0e48be946e22ac', 'getAgentInfoByIP(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param agentIp         为空则获取全部\n * @return JSONString\n\n * var res = aomApi.getAgentInfoByIP(...);\n */\n', '通过ip获取agent信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('701b26d51cf44f2eaed468e5d41555b1', 'getCache(String arg0, String arg1)', 'String', '/**\n *\n * @param cacheName  缓存名\n * @param key  缓存key\n */\n\nvar cacheName = \"\";\nvar key = \"\";\nvar res = kutils.getCache(cacheName, key);\n', '获取缓存', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('703a901f949742b783d7af25e41360bb', 'toExcel(String arg0, String arg1)', 'String', '/**\n * 渲染Excel\n *\n * @param templateLocation  模板文件路径\n * @param variables         变量名，json字符串\n * @return 渲染结果\n *  成功： {\"data\":\"tmp/xxx.xlsx\",\"success\":true}\n *  失败： {\"errorMsg\":\"异常信息\",\"success\":false}\n */', '渲染Excel', '97d4c6198b2a45f696ce274d01b0a8f9', '2022-09-06 16:33:22', '238f846ce9824d60adebe11c2a795b38', '2022-09-06 16:33:22', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('70b82d169e6449dda415dd790f3ed71e', 'getMethodDescriptionClass()', 'Class', '/**\n *\n * @return MethodDescription注解的class对象\n */\n\n var res = kutils.getMethodDescriptionClass();\n', '获取MethodDescription注解的class对象', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('720a7a45293d40a5959b626b59c50e5a', 'getNow(String arg0)', 'String', '/**\n *\n * @param format 时间格式\n * @return  格式化时间\n */\n\nvar format = \"\";\nvar res = kutils.getNow(format);\n', '格式化当前时间', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('73af4800d323421ba0baa8ed40f7bea1', 'getFlowParams(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param scriptId   组件Id\n * @return JSONString\n\n * var res = aomApi.getFlowParams(...);\n */\n', '获取组件信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7431488bab3b4303b7e2007d3e85c1bc', 'rsaEncode(String arg0, String arg1)', 'String', '/**\n *\n * @param text  需要加密的数据\n * @param publicKey  key\n * @return  加密后的数据\n */\n\nvar text = \"\";\nvar publicKey = \"\";\nvar res = kutils.rsaEncode(text, publicKey);\n', 'RSA加密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('75b02015a40f4796bbc60481f77952d5', 'updateCCStatus(String arg0, String arg1)', 'void', '/**\n *\n * 更新抄送记录为已阅\n * @param instId 流程实例id\n * @param actorIds 参与者id\n\nvar res = flowInst.updateCCStatus(\'a\', \'f\');\n', '更新抄送记录为已阅', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('76c3d29b7fdb435daa8c461ee8d8767b', 'getWorkItems(String arg0, String arg1)', 'String', '/**\n *\n * 根据filter分页查询工作项（包含process、inst、task三个实体的字段集合）\n * @param page 分页对象\n * @param filter 查询过滤器\n * @return json(List<WorkItem>) 活动工作项集合\n\nvar page = \'{\"pageNo\":1,\"pageSize\":15}\';\nvar filter = \'{\"operator\":\"1\"}\';\nvar res = flowTask.getWorkItems(page, filter);\n', '查询工作项', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('779f99950dd5411dbc3159298801d5c7', 'fileDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param key\n * @param fileName : 文件名\n * @return\n */\n\n\n var key = \"\";\n var fileName = \"\";\n var res = kutils.fileDecode(key, fileName);\n', '文件内容解密:国密4 ECB模式加密，解密本地文件', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('77e3c5a560244b20963d654b004edd06', 'httpPut(String arg0, String arg1, Map<String, String> arg2, String arg3)', 'String', '/**\n *\n * @param url 请求地址\n * @param contentType Content-Type\n * @param headers 请求头 Map<String,String>\n * @param content 请求参数，json字符串格式\n * @return\n * @throws Exception\n */\n\nvar url = \"\";\nvar contentType = \"\";\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar headers = new HashMap();\nheaders.put(\'header1\',\'111\');\n\nvar content = {\n    \"a\": \"abc\"\n };\n\nvar res = kutils.httpPut(url, contentType, headers, content);\n', 'http put请求，请求参数是map格式', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7855118f18724b9d86fd48de06713353', 'httpGet(String arg0, String arg1, Map<String, String> arg2)', 'String', '/**\n * @param url 请求url\n * @param contentType\n * @param headers 请求头,Map<String,String>\n * @return 请求响应\n * @throws Exception 请求发生异常\n */\n\n var url = \"\";\n var contentType = \"\";\n var headers = {};\n var res = kutils.httpGet(url, contentType, headers);\n', 'http get请求', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7890ef658ce840f6adfe06dc0b20b6ac', 'getNextTable(String arg0, String arg1, int arg2, String arg3, String arg4, String arg5, String arg6, String arg7, String arg8, String arg9, List<String> arg10, long arg11)', 'String', '/**\n *\n * @param host\n * @param version v1、v2c、v3\n * @param port 端口\n * @param community 团体字（v1, v2c）\n * @param userName 用户名 （v2及以下版本填null)\n * @param securityLevel 安全级别（v2及以下版本填null)：分别为noAuthNoPriv（不认证也不加密）、authNoPriv（认证但是不加密）、authPriv（既认证又加密）\n * @param authenticationProtocol 验证协议（v2及以下版本填null)：MD5、SHA\n * @param authenticationPassphrase 验证字符串（v2及以下版本填null)\n * @param privacyProtocol 加密协议（v2及以下版本填null)：DES、3DES、AES128、AES192、AES256\n * @param privacyPassphrase 加密字符串（v2及以下版本填null)\n * @param oids 每个oid对应表的每一列\n * @param timeout 超时时间，毫秒单位\n * @return JSONString\n *\n * var oids = [\".1.3.6.1.2.1.1\"];\n * var tableRows =  snmpApi.getNextTable(\"1.1.1.1\", \"v2c\", 161, \"public\", null, null, null, null, null, null, oids, 5000);\n * tableRows = JSON.parse(tableRows);\n * for (var i in tableRows) {\n *      var row = tableRows[i];\n *      var index = row[\"index\"];\n *      var variables = row[\"columns\"];\n * }\n */\n', '使用getnext获取表对象的列变量信息，每个oid对应表的每一列', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('790ecca431084fe6a382bb2caea9428a', 'executeAndJumpTask(String arg0, String arg1, Map<String, Object> arg2, String arg3)', 'String', '/**\n *\n * 驳回并跳转：根据任务主键ID，操作人ID，参数列表执行任务，并且根据nodeName跳转到任意节点\n * 1、nodeName为null时，则跳转至上一步处理\n * 2、nodeName不为null时，则任意跳转，即动态创建转移\n * @param taskId 任务主键ID\n * @param operator 操作人主键ID\n * @param args 参数列表\n * @param nodeName 跳转的节点名称\n * @return List<Task> 任务集合`\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar map = new HashMap();\nmap.put(\'a\', \'a\');\nvar res = flowExecute.executeAndJumpTask(\'a\', \'1\', map, null);\n', '跳转到任意节点', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('792f9544f7754189b71e2f78e6ceccac', 'startFlow(Map<String, String> arg0, String arg1, boolean arg2, List<Map<String, Object>> arg3, List<Map<String, Object>> arg4, List<Map<String, Object>> arg5)', 'String', '/**\n * @param aomServerParam\n * @param flowId\n * @param isQueue\n * @param objectParams 节点参数 List<Map<String, Object>>\n * @param agentParams 机器参数 List<Map<String, Object>>\n * @param vclParams 组件节点参数 List<Map<String, Object>>\n * @return JSONString\n *\n * var aomServerParam = {\n *    \"serverip\":\"\",\n *    \"serverport\":\"\",\n *    ......\n * }\n *\n * var objectParam1 = {\n *    \"objectName\": \"\",\n *    \"paramName\": \"\",\n *    \"paramValue\": \"\",\n *    \"paramIsDes\": false\n * }\n * var objectParamList = [];\n * objectParamList.push(objectParam1);\n\n * var agentParam1 = {\n *    \"agentParamName\": \"\",\n *    \"agentParamValue\": \"\"\n * }\n * var agentParamList = [];\n * agentParamList.push(agentParam1);\n\n * var vclParam1 = {\n *    \"VCLObjectName\": \"\",\n *    \"VCLParamValue\": \"\"\n * }\n * var vclParamList = [];\n * vclParamList.push(vclParam1);\n * var result = aomApi.startFlow(aomServerParam, \"flowId\", true, objectParamList, agentParamList, vclParamList)\n *\n */\n', '执行流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7a067132a1494e6bb9b8b892c6cc1a2e', 'httpPostBody(String arg0, String arg1, Map<String, String> arg2, String arg3)', 'String', '/**\n * @param url 请求url\n * @param contentType\n * @param headers 请求头，Map<String,String>\n * @param content 请求参数，json字符串格式\n * @return 请求响应\n * @throws Exception 请求发生异常\n */\n\nvar url = \"\";\nvar contentType = \"\";\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar headers = new HashMap();\nheaders.put(\'header1\',\'111\');\n\n var content = {\n    \"a\": \"abc\"\n };\n content = JSON.stringify(content);\n var res = kutils.httpPostBody(url, contentType, headers, content);\n', 'http post请求，请求参数是json字符串', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7bd6e7e68cd6496eb9f6c9c213766343', 'testException(String arg0)', 'String', '', '', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7c45a6fbaa284c3683a1ce7473fde581', 'httpFileUpload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3, Map<String, String> arg4)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list 文件信息\n * @param params Map<String,String> 其他参数\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// 文件在服务器上的相对路径，包括文件名，例：upload/test/test.pdf\nvar fileLocal = \"upload/test/test.pdf\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件内容\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'filename\', fileLocal);\nlist.add(fileMap);\n\n// 除了文件外的其他请求参数\nvar params = new HashMap();\nparams.put(\"abc\", \"123\");\n\nvar res = kutils.httpFileUpload(key, url, headers, list, params);\n', '需要上传文件的请求，还有其他参数', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7cf9b5c9f8464d75916de8f44fe0a3f1', 'getArrayList(String arg0, int arg1)', 'List', '', '', '8', '2022-07-19 15:02:21', 'd4040ae0800844d99406157b798bae01', '2022-07-19 15:02:21', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7dbc81de11e147528990b6dc49c62dca', 'getFileFromZip(String arg0, String arg1, String arg2)', 'String', '/**\n *\n * @param fromDir 压缩文件路径和压缩包名\n * @param targetFileName 目标文件名称\n * @param targetDir 提取文件存放路径,以/结尾\n * @throws IOException 从压缩包提取文件时发生异常\n */\n String path = \"./ext/kutils/kutilsplugin-jar-with-dependencies.jar\";\n String targetFileName = \"clz.ini\";\n String targetDir = \"./pluginDirectory/\";\n var res = kutils.getFileFromZip(path, targetFileName, targetDir);\n', '从指定压缩包提取指定文件到指定目录', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7e4ff47ed9254fbfb455bc241e7bb436', 'httpFileUpload(String arg0, String arg1, Map<String, String> arg2, List<Map> arg3, Map<String, String> arg4)', 'String', '/**\n *\n * @param key 请求参数中文件的key,例请求参数{\"file\":文件内容},这个key就是file\n * @param url\n * @param headers Map<String,String>\n * @param list 文件信息\n * @param params Map<String,String> 其他参数\n * @return\n * @throws Exception\n */\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar ArrayList = Java.type(\'java.util.ArrayList\')\n\n// 文件名\nvar fileName = \"test.pdf\";\n// 文件在服务器上的相对路径，包括文件名，例：upload/test/test.pdf\nvar fileLocal = \"upload/test/test.pdf\";\n\n// 请求体的key\nvar key = \"file\";\nvar url = \"\";\nvar headers = {};\n\n// 请求体的文件内容\nvar list = new ArrayList();\nvar fileMap = new HashMap();\nfileMap.put(\'name\', fileName);\nfileMap.put(\'filename\', fileLocal);\nlist.add(fileMap);\n\n// 除了文件外的其他请求参数\nvar params = new HashMap();\nparams.put(\"abc\", \"123\");\n\nvar res = kutils.httpFileUpload(key, url, headers, list, params);\n', '需要上传文件的请求，还有其他参数', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7e93cf145e744918a3a1dd84c25eb86e', 'getFlowList(Map<String, String> arg0)', 'String', '/**\n *\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @return JSONString\n\n * var res = aomApi.getFlowList(...);\n */\n', '获取流程列表', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7ed56dc430e54c3cbbc1bbf64a5cc16e', 'fileCopy(String arg0, String arg1)', 'void', '/**\n *\n * @param oldFileName\n * @param newFileName\n */\n\n\n var oldFileName = \"\";\n var newFileName = \"\";\n kutils.fileCopy(oldFileName, newFileName);\n', '文件拷贝', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('7f92842321964889833982429003be79', 'removeCache(String arg0)', 'void', '/**\n *\n * @param cacheName  缓存名\n */\n\nvar cacheName = \"\";\nvar res = kutils.removeCache(cacheName);\n', '清除缓存列表', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
