INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('8636a40f95b341468121516851967bad', 'setCache(String arg0, String arg1, String arg2, int arg3)', 'void', '/**\n *\n * @param cacheName  缓存名\n * @param key  缓存key\n * @param value  缓存value\n * @param maxLifetime  过期时间 int\n */\n\nvar cacheName = \"\";\nvar key = \"\";\nvar value = \"\";\nvar maxLifetime = 6000;\nvar res = kutils.setCache(cacheName, key, value);\n', '设置缓存和过期时间', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
