INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a30053786d4e40cdaf8f0ecf552d2c74', 'fileReadBase64(String arg0)', 'String', '/**\n *\n * @param fileName  文件名\n * @return  base64编码\n * @throws Exception    异常\n */\n\n\n var fileName = \"\";\n var res = kutils.fileReadBase64(fileName);\n', '读取文件转为base64', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a34e5fa7cccd43efaa64b5f0e23a2cc0', 'addTextWatermark(String arg0, String arg1, String arg2, String arg3, int arg4, int arg5, float arg6, boolean arg7)', 'String', '/**\n *\n * @param srcImageBase64 base64图片地址\n * @param text           水印内容\n * @param hexColor       文字颜色(hex形式,例如#FFCCEE)\n * @param fontName       字体,如 \"微软雅黑\"、\"黑体\"\n * @param fontStyle      字体样式,粗体、斜体、正常等\n * @param fontSize       字体大小\n * @param alpha          水印透明度 必须是范围[0.0,1.0](包含边界值)的一个浮点数\n * @param isFullScreen   是否全屏水印,默认false,为右下角水印\n * @return 带水印的base64图片\n */\n\n var srcImageBase64 = \"\";\n var text = \"\";\n var hexColor = \"\";\n var fontName = \"\";\n var fontStyle = 20;\n var fontSize = 20;\n var alpha = 0.5;\n var isFullScreen = false;\n var res = kutils.addTextWatermark(srcImageBase64, text, hexColor, fontName, fontStyle, fontSize, alpha);\n', '添加文字水印', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a3e619de869443f3b4fb362504da4f10', 'execute(Map<String, String> arg0, String arg1, String arg2)', 'String', '/**\n * @param map    连接参数\n * @param dbName 数据库名\n * @param sql    执行的sql\n * @return 执行结果\n */\n', '执行SQL语句', '7d52d882739f422793c456e2a77cc746', '2022-08-31 14:07:55', '8c263f81d2b14784906787d67ce58b47', '2022-08-31 14:07:55', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a3ea24b30a49428493e097c6b9e88260', 'getTableColumnAndType(Map<String, String> arg0, String arg1, String arg2)', 'String', '', '', '0326119307e146ab97be95cc5d029f4c', '2022-07-19 09:18:35', '8c263f81d2b14784906787d67ce58b47', '2022-07-19 09:18:35', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a42acb5960d54a6f89c318e3a656298b', 'shell(String arg0, int arg1, String arg2, String arg3, String arg4, long arg5, String arg6)', 'String', '/**\n  * @param host 主机ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param command 命令\n  * @param timeout 超时时间(毫秒)\n  * @param charset 编码\n  * @return\n  * @throws Exception\n  *\n  * var host = \"10.11.2.215\", port = 22, username = \"root\", password = \"Kingsware##1228\", command = \"echo hello\", timeout = 30000, charset = \"UTF-8\";\n  * var result = sshApi.shell(host, port, username, password, command, timeout, charset);\n  *\n  */\n', 'ssh执行shell脚本', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a66ab2eb489b495ba3df768fe70bf4b7', 'getTargetValueLst(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param programId\n * @return JSONString\n\n * var res = aomApi.getTargetValueLst(...);\n */\n', '获取整个应用下的流程节点信息', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a7cfe7cbe17c4c799ce1e2b2187230ef', 'getFileNamesByDir(String arg0)', 'String', '/**\n * @param directory 目录路径\n * @return 目录下的所有文件名称\n * @throws Exception 获取目录下的所有文件名称时发生异常\n */\n var directory = \"./lib/\";\n var res = kutils.getLibJar(directory);\n', '根据一个目录路径获取该目录下的所有文件名称', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a7ee6a5c8fcd48b4a07406d76adc8fb6', 'getPid(String arg0, int arg1, String arg2, String arg3, long arg4, String arg5, String arg6)', 'String', ' /**\n  *\n  * @param host ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param timeout 超时时长\n  * @param charset 编码\n  * @param appName jar包名称(不要写后缀.jar)\n  * @return pid\n  *\n  * var res = monitor.getPid(\"ip\",\"port\",\"username\",\"password\", 30000, \"UTF-8\", \"kfaas-jar-with-dependencies\")\n  */\n', '根据jar包名称获取pid', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('a9808c62ae3c47f58a2f6630e12068d7', 'checkGc(String arg0, int arg1, String arg2, String arg3, long arg4, String arg5, String arg6, String arg7, String arg8, String arg9, String[) arg10, int arg11, String arg12, int arg13, int arg14]', 'void', '/**\n * @param host ip\n * @param port 端口\n * @param username 登录名\n * @param password 密码\n * @param timeout 超时时长\n * @param charset 编码\n * @param jarName jar包名称\n * @param appName app名称\n * @param mailHost 邮箱ip\n * @param mailUsername 邮箱登录名\n * @param mailPassword 邮箱密码\n * @param address 发送地址数组\n * @param num 线程数量\n * @param arthasPath arthas工具路径\n * @param interval 时间间隔\n * @param diff GC次数差值\n *\n * monitorApi.checkGc(\"ip\",\"port\",\"username\",\"password\", 30000, \"UTF-8\", \"kfaas\",\n *                    \"mailHost\", \"mailUsername\", \"mailPassword\", [address],\n *                    10, \"/usr/local/arthas\", 30, 60)\n */\n', '检查gc', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
