INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('ad982dd996f44dfda3f36e808c9f5292', 'startFlow(Map<String, String> arg0, String arg1)', 'String', '/**\n *\n * @param AomServerParam {serverip: \"\",serverport:\"\",username:\"\",password:\"\"}\n * @param flowId\n * @return JSONString\n\n * var res = aomApi.startFlow(...);\n */\n', '执行流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
