INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('b0e9c45944a04916a40d9d23ce43a08f', 'getProcesss(String arg0, String arg1)', 'String', '/**\n *\n * 根据给定的参数列表args分页查询process\n * @param page 分页对象\n * @param filter 查询过滤器\n * @return List<Process> 流程定义对象集合\n\nvar page = \'{\"pageNo\":1,\"pageSize\":15}\';\nvar filter = \'{\"operator\":\"1\"}\';\nvar res = flowDefine.getProcesss(page, filter);\n', '根据给定的参数列表args分页查询process', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('b305242d9f1945b28aa8d8672b86f9ac', 'setCache(String arg0, String arg1, String arg2)', 'void', '/**\n *\n * @param cacheName  缓存名\n * @param key  缓存key\n * @param value  缓存value\n */\n\nvar cacheName = \"\";\nvar key = \"\";\nvar value = \"\";\nvar res = kutils.setCache(cacheName, key, value);\n', '设置缓存，没有过期时间', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('b3dd0152fe5d47d9bb621dd815ff43bb', 'executeTask(String arg0, String arg1, Map<String, Object> arg2)', 'String', '/**\n *\n * 执行：根据任务主键ID，操作人ID，参数列表执行任务\n * @param taskId 任务主键ID\n * @param operator 操作人主键ID\n * @param args 参数列表\n * @return List<Task> 任务集合\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar map = new HashMap();\nmap.put(\'a\', \'a\');\nvar res = flowExecute.executeTask(\'a\', \'1\', map);\n', '根据任务主键ID，操作人ID，参数列表执行任务', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('b4a5407a796d4f3fa153a4058bab866e', 'sm4Decode_ECB(String arg0, String arg1)', 'String', '/**\n *\n * @param key\n * @param text  需要解密的数据\n * @return  解密后的数据\n */\n\nvar key = \"\";\nvar text = \"\";\nvar res = kutils.sm4Decode_ECB(key, text);\n', '国密4ECB模式解密', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
