INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('c080b4fc5e9542218d6ddc4b55478cab', 'resume(String arg0, String arg1)', 'String', '/**\n *\n  * 唤醒：根据历史任务主键id，操作人唤醒历史任务\n  * 该方法会导致流程状态不可控，请慎用\n  *\n  * @param taskId   历史任务id\n  * @param operator 操作人id\n  * @return json(Task) 唤醒后的任务对象\n\nvar res = flowTask.resume(\'a\', \'1\');\n', '根据历史任务主键id，操作人唤醒历史任务', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
