INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('c593c6b7e5044544823341834677a3c6', 'getNativeNextNodeModels(String arg0, String arg1)', 'List', '/**\n *\n * 根据流程定义模型id和任务定义模型name获取下个节点模型对象\n * @param processId 流程定义模型id\n * @param taskName 任务定义模型name（注意是name字段，区别于displayName字段）\n * @return java对象List<NodeModel>\n\nvar res = flowDefine.getNativeNextNodeModels(\'a\', \'1\');\n', '根据流程定义模型id和任务定义模型name获取下个节点模型对象', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('c728a2f2b1764629abcb28c0e07f51b1', 'startInstanceById(String arg0, String arg1, Map<String, Object> arg2)', 'String', '/**\n *\n * 根据流程定义ID，操作人ID，参数列表启动流程实例\n * @param id 流程定义ID\n * @param operator 操作人ID\n * @param args 参数列表\n * @return Workflow 流程实例json\n\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar map = new HashMap();\nmap.put(\'a\', \'a\');\nvar res = flowRepository.startInstanceById(\'aa\', \'1\', map);\n', '根据流程定义ID，操作人ID，参数列表启动流程实例', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('c7567277d23d4f5a8c74c8b0ae04ad33', 'rsaDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param text  需要解密的数据\n * @param publicKey  key\n * @return  解密后的数据\n */\n\nvar text = \"\";\nvar publicKey = \"\";\nvar res = kutils.rsaDecode(text, publicKey);\n', 'RSA解密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('c8e5a946f6324c6db8cf64bf3018e532', 'addTextWatermark(String arg0, String arg1, String arg2, String arg3, int arg4, int arg5, float arg6, boolean arg7)', 'String', '/**\n *\n * @param srcImageBase64 base64图片地址\n * @param text           水印内容\n * @param hexColor       文字颜色(hex形式,例如#FFCCEE)\n * @param fontName       字体,如 \"微软雅黑\"、\"黑体\"\n * @param fontStyle      字体样式,粗体、斜体、正常等\n * @param fontSize       字体大小\n * @param alpha          水印透明度 必须是范围[0.0,1.0](包含边界值)的一个浮点数\n * @param isFullScreen   是否全屏水印,默认false,为右下角水印\n * @return 带水印的base64图片\n */\n\n var srcImageBase64 = \"\";\n var text = \"\";\n var hexColor = \"\";\n var fontName = \"\";\n var fontStyle = 20;\n var fontSize = 20;\n var alpha = 0.5;\n var isFullScreen = false;\n var res = kutils.addTextWatermark(srcImageBase64, text, hexColor, fontName, fontStyle, fontSize, alpha);\n', '添加文字水印', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('c94f7900859a4f349e84cb979aa9acf2', 'getTask(String arg0)', 'String', '/**\n *\n * 根据任务ID获取任务对象\n *\n * @param taskId 任务id\n * @return json(Task) 任务对象\n\nvar res = flowTask.getTask(\'a\');\n', '根据任务ID获取任务对象', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
