INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('cbd73a99f1f045a684d160b0c7a3644b', 'stopFlow(Map<String, String> arg0, String arg1)', 'String', '/**\n * @param serverIp\n * @param serverPort\n * @param username\n * @param password\n * @param execId\n * @return JSONString\n\n * var res = aomApi.stopFlow(...);\n */\n', '停止流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('cd9a2a4e46a64b9cafb21c327ae0b9f5', 'startInstanceById(String arg0)', 'String', '/**\n *\n * 根据流程定义ID启动流程实例\n * @param id 流程定义ID\n * @return Workflow 流程实例\n\nvar res = flowRepository.startInstanceById(\'aa\');\n', '根据流程定义ID启动流程实例', '064ace9da0ef4731816886cb9b974ea9', '2022-09-19 17:11:30', '3db2cfb7cbb84113a902808aef44f2a0', '2022-09-19 17:11:30', NULL, 0);
