INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('ce13b4d221e546a6a241e869dacef30e', 'fileEncode(String arg0, String arg1, String arg2)', 'void', '/**\n *\n * @param key\n * @param content : 文件内容\n * @param fileName : 文件名\n * @return\n */\n\n\n var key = \"\";\n var content = \"\";\n var fileName = \"\";\n kutils.fileEncode(key, content, fileName);\n', '文件内容加密:国密4 ECB模式加密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('d034ceac70aa4c0eb489c1fce9fc8b2a', 'getBulkTable(String arg0, String arg1, int arg2, String arg3, String arg4, String arg5, String arg6, String arg7, String arg8, String arg9, List<String> arg10, long arg11, int arg12)', 'String', '/**\n *\n * @param host\n * @param version v1、v2c、v3\n * @param port 端口\n * @param community 团体字（v1, v2c）\n * @param userName 用户名 （v2及以下版本填null)\n * @param securityLevel 安全级别（v2及以下版本填null)：分别为noAuthNoPriv（不认证也不加密）、authNoPriv（认证但是不加密）、authPriv（既认证又加密）\n * @param authenticationProtocol 验证协议（v2及以下版本填null)：MD5、SHA\n * @param authenticationPassphrase 验证字符串（v2及以下版本填null)\n * @param privacyProtocol 加密协议（v2及以下版本填null)：DES、3DES、AES128、AES192、AES256\n * @param privacyPassphrase 加密字符串（v2及以下版本填null)\n * @param oids\n * @param timeout\n * @param numberOfRowsPerChunk\n * @return JSONString\n * @throws IOException\n *\n * var oids = [\".1.3.6.1.2.1.1\"];\n * var tableRows =  snmpApi.getBulkTable(\"1.1.1.1\", \"v2c\", 161, \"public\", null, null, null, null, null, null, oids, 5000, 5);\n * tableRows = JSON.parse(tableRows);\n * for (var i in tableRows) {\n *      var row = tableRows[i];\n *      var index = row[\"index\"];\n *      var variables = row[\"columns\"];\n * }\n */\n', '使用getbulk获取表对象的列变量信息，每个oid对应表的每一列', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('d1bf590019ee456db4f5c11618eda296', 'aesDecode(String arg0, String arg1)', 'String', '/**\n *\n * @param str base64加密的密文\n * @param key base64加密后的密钥\n * @return 解密后的数据\n * @throws Exception\n */\n\n var str = \"\";\n var key = \"\";\n var res = kutils.aesDecode(str, key);\n', 'AES解密', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
