INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('e35b3758955d45109ec3e1501c256481', 'exportExcel(Map<String, String> arg0, String arg1, String arg2, String arg3)', 'String', '/**\n * @param map       连接参数\n * @param dbName    数据库名\n * @param tableName 表名\n * @param excelNum  导出数量\n * @return excel批量数据\n */\n', '批量导出Excel', '7d52d882739f422793c456e2a77cc746', '2022-08-31 14:07:55', '8c263f81d2b14784906787d67ce58b47', '2022-08-31 14:07:55', NULL, 0);
