INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('e80afa3ef1cc48fca67e99dbbe027976', 'httpPostForm(String arg0, String arg1, Map<String, String> arg2, Map<String, String> arg3)', 'String', '/**\n *\n * @param url 请求地址\n * @param contentType Content-Type\n * @param headers 请求头 Map<String,String>\n * @param formParams 请求体，Map<String,String>\n * @return\n * @throws Exception\n */\nvar url = \"\";\nvar contentType = \"\";\nvar HashMap = Java.type(\'java.util.HashMap\');\nvar headers = new HashMap();\nheaders.put(\'header1\',\'111\');\nvar formParams = new HashMap();\nformParams.put(\'header1\',\'111\');\n\nvar res = kutils.httpPostForm(url, contentType, headers, formParams);\n', 'http post请求，请求参数是map格式', '9', '2022-09-15 16:24:45', 'd4040ae0800844d99406157b798bae01', '2022-09-15 16:24:45', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('e9c4517753d246a992b7a7d5fa40adcd', 'exec(String arg0, int arg1, String arg2, String arg3, String arg4, long arg5, String arg6)', 'String', '/**\n  * @param host 主机ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param command 命令\n  * @param timeout 超时时间(毫秒)\n  * @param charset 编码\n  * @return\n  * @throws Exception\n  *\n  * var host = \"10.11.2.215\", port = 22, username = \"root\", password = \"Kingsware##1228\", command = \"echo hello\", timeout = 30000, charset = \"UTF-8\";\n  * var result = sshApi.exec(host, port, username, password, command, timeout, charset);\n  *\n  */\n', 'ssh执行命令', '518ead98cd5247eea5e0dd9f3f8ff020', '2022-07-14 12:27:21', '8c263f81d2b14784906787d67ce58b47', '2022-07-14 12:27:21', NULL, 0);
