INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('f0e534b9ad2f4c4580172aebca32364c', 'startFlow(Map<String, String> arg0, String arg1, String arg2, boolean arg3, List<Map<String, Object>> arg4, List<Map<String, Object>> arg5, List<Map<String, Object>> arg6)', 'String', '/**\n * @param aomServerParam\n * @param flowId\n * @param execId\n * @param isQueue\n * @param objectParams 节点参数 List<Map<String, Object>>\n * @param agentParams 机器参数 List<Map<String, Object>>\n * @param vclParams 组件节点参数 List<Map<String, Object>>\n * @return JSONString\n *\n * var aomServerParam = {\n *    \"serverip\":\"\",\n *    \"serverport\":\"\",\n *    ......\n * }\n *\n * var objectParam1 = {\n *    \"objectName\": \"\",\n *    \"paramName\": \"\",\n *    \"paramValue\": \"\",\n *    \"paramIsDes\": false\n * }\n * var objectParamList = [];\n * objectParamList.push(objectParam1);\n\n * var agentParam1 = {\n *    \"agentParamName\": \"\",\n *    \"agentParamValue\": \"\"\n * }\n * var agentParamList = [];\n * agentParamList.push(agentParam1);\n\n * var vclParam1 = {\n *    \"VCLObjectName\": \"\",\n *    \"VCLParamValue\": \"\"\n * }\n * var vclParamList = [];\n * vclParamList.push(vclParam1);\n * var result = aomApi.startFlow(aomServerParam, \"flowId\", \"execId\", true, objectParamList, agentParamList, vclParamList)\n *\n */\n', '执行流程', '6', '2022-08-17 15:28:30', '74f2a9fd76c6466a8b7566eeb717dba7', '2022-08-17 15:28:30', NULL, 0);
