INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('fca0c0ad4a0e4d04b52095c8b90dee23', 'exec(String arg0, int arg1, String arg2, String arg3, String arg4, long arg5, String arg6)', 'String', '/**\n  * @param host 主机ip\n  * @param port 端口\n  * @param username 登录名\n  * @param password 密码\n  * @param command 命令\n  * @param timeout 超时时间(毫秒)\n  * @param charset 编码\n  * @return\n  * @throws Exception\n  *\n  * var host = \"10.11.2.215\", port = 22, username = \"root\", password = \"Kingsware##1228\", command = \"echo hello\", timeout = 30000, charset = \"UTF-8\";\n  * var result = sshApi.exec(host, port, username, password, command, timeout, charset);\n  *\n  */\n', 'ssh执行命令', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
