INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('feefca04944749a79f84baef99689b4c', 'getVariable(String arg0, String arg1, int arg2, String arg3, String arg4, String arg5, String arg6, String arg7, String arg8, String arg9, String arg10, long arg11)', 'String', '/**\n * @param host\n * @param version v1、v2c、v3\n * @param port 端口\n * @param community 团体字（v1, v2c）\n * @param userName 用户名 （v2及以下版本填null)\n * @param securityLevel 安全级别（v2及以下版本填null)：分别为noAuthNoPriv（不认证也不加密）、authNoPriv（认证但是不加密）、authPriv（既认证又加密）\n * @param authenticationProtocol 验证协议（v2及以下版本填null)：MD5、SHA\n * @param authenticationPassphrase 验证字符串（v2及以下版本填null)\n * @param privacyProtocol 加密协议（v2及以下版本填null)：DES、3DES、AES128、AES192、AES256\n * @param privacyPassphrase 加密字符串（v2及以下版本填null)\n * @param oid 对象标识符\n * @param timeout 超时时间，毫秒单位\n * @return String\n * @throws IOException\n *\n * var variable = snmpApi.getVariable(\"1.1.1.1\", \"v2c\", 161, \"kingsware\", null, null, null , null, null, null, \".1.3.6.1.2.1.1.5.0\", 5000);\n * var result = variable;\n */\n', '使用get方式获取单个标量的信息，相当于snmpget命令', '655fdd569b8c4846a8e5e87acda44065', '2022-08-09 15:08:14', 'd4040ae0800844d99406157b798bae01', '2022-08-09 15:08:14', NULL, 0);
INSERT INTO ext_plugin_interface (id, name, resp_type, content, description, plugin_id, create_time,create_user, update_time, update_user, deleted) VALUES ('ffd8768a0fb641379f0747371b4965e8', 'urlEncode(String arg0)', 'String', '/**\n *\n * @param text  文本\n * @return  编码文本\n */\n\nvar text = \"\";\nvar res = kutils.urlEncode(text);\n', 'url编码', '178a51e75e0846dba698eee465751085', '2022-07-06 15:21:46', 'd4040ae0800844d99406157b798bae01', '2022-07-06 15:21:46', NULL, 0);
